using UnityEngine;
using Climbing;

public class TeleportPlayer
{
    public static string Run()
    {
        ClimbController cc = Object.FindObjectOfType<ClimbController>();
        if (cc == null) return "Player not found (no ClimbController)";

        GameObject pm = cc.gameObject;
        RaycastHit hit;
        // Raycast from slightly above current position to 100 units down
        if (Physics.Raycast(pm.transform.position + Vector3.up * 0.5f, Vector3.down, out hit, 100f))
        {
            pm.transform.position = hit.point + Vector3.up * 0.05f;
            return $"Teleported player {pm.name} to ground: {hit.collider.name} at {hit.point}";
        }

        return "No ground found below player to teleport to.";
    }
}
